"use client";
import React, { useState } from 'react';

export default function SubscribeButton() {
  const [subStatus, setSubStatus] = useState<'idle' | 'loading' | 'success'>('idle');

  const handleSubscribe = async () => {
    setSubStatus('loading');
    // ... [Previous push logic here] ...
    setSubStatus('success');
  };

  return (
    <button 
      onClick={handleSubscribe}
      className={`px-10 py-3 rounded-full font-black uppercase tracking-widest transition-all ${
        subStatus === 'success' ? 'bg-green-500 text-black' : 'bg-white text-blue-900 hover:scale-105'
      }`}
    >
      {subStatus === 'idle' ? "Notify Me" : subStatus === 'loading' ? "Connecting..." : "✓ Subscribed"}
    </button>
  );
}